mapper.select:
SELECT v.id, v.visit_no AS visitNo, v.registration_id AS registrationId, r.reg_no AS regNo, v.patient_id AS patientId, p.name AS patientName, v.staff_id AS staffId, s.name AS staffName, v.visit_time AS visitTime, v.chief_complaint AS chiefComplaint, v.diagnosis, v.status FROM outpatient_visit v LEFT JOIN registration r ON r.id = v.registration_id LEFT JOIN patient p ON p.id = v.patient_id LEFT JOIN staff s ON s.id = v.staff_id
AND v.status = #{status} AND v.staff_id = #{staffId}
ORDER BY v.visit_time DESC

mapper.update:
UPDATE outpatient_visit
chief_complaint = #{chiefComplaint}, diagnosis = #{diagnosis}, status = #{status},
WHERE id = #{id}
